import { useEffect, useRef, useState } from 'react';
import { Input, Table, Typography } from 'antd';
import config from '../config';
import './index.css';

function App() {
  const [pools, setPools] = useState([]);
  const [token0, setToken0] = useState('');
  const [token1, setToken1] = useState('');
  const [gtTvl, setGtTvl] = useState('100000');
  const [ltTvl, setLtTvl] = useState('');
  const [chain, setChain] = useState('');
  const [project, setProject] = useState('');
  const [tableCols] = useState([
    {
      title: 'POOL',
      dataIndex: 'pool',
      fixed: 'left',
      width: 200,
      render: (text, record) => (
        <Typography.Link href={record.url} target="_blank" rel="noreferrer">
          {text}
        </Typography.Link>
      )
    },
    {
      title: 'APY(BASE)',
      dataIndex: 'apyBase',
      defaultSortOrder: 'descend',
      sorter: (a, b) => a.apyBase - b.apyBase,
      render: text => (text ? `${text}%` : '')
    },
    {
      title: 'APY',
      dataIndex: 'apy',
      defaultSortOrder: 'descend',
      sorter: (a, b) => a.apy - b.apy,
      render: text => `${text}%`
    },
    {
      title: 'APY(7D)',
      dataIndex: 'apyPct7D',
      defaultSortOrder: 'descend',
      sorter: (a, b) => a.apyPct7D - b.apyPct7D,
      render: text => (text ? `${text}%` : '')
    },
    {
      title: 'PROJECT',
      dataIndex: 'project'
    },
    {
      title: 'CHAIN',
      dataIndex: 'chain'
    },
    {
      title: 'VOL',
      dataIndex: 'volumeUsd1d'
    },
    {
      title: 'TVL',
      dataIndex: 'tvlUsd'
    },
    {
      title: 'TOKEN',
      dataIndex: 'underlyingTokens',
      render: (text, record) => {
        const tokens = record.symbol.split('-');
        return (
          <div className="defi-token-list">
            {tokens.map((_, i) => {
              return (
                <Typography.Paragraph key={_} copyable={text ? { text: text[i] } : false} style={{ margin: 0, marginRight: '1rem' }}>
                  {_}
                </Typography.Paragraph>
              );
            })}
          </div>
        );
      }
    }
  ]);
  const [tableData, setTableData] = useState([]);

  const ref = useRef(null);
  const tableRef = useRef(null);
  ref.current = async () => {
    const protocols = await (await fetch(config.api.protocols)).json();
    const { data: pools } = await (await fetch(config.api.pools)).json();

    const dexes = protocols.filter(_ => _.category === 'Dexes').map(_ => _.slug);
    const dexPools = pools.filter(_ => {
      if (!dexes.includes(_.project)) return false;
      return true;
    });

    setPools(dexPools);
  };
  tableRef.current = () => {
    const data = [];
    pools
      .filter(_ => {
        const { apy } = _;
        if (apy) return true;
        return false;
      })
      .filter(_ => {
        if (chain) {
          if (_.chain.toUpperCase().includes(chain.toUpperCase())) return true;
          return false;
        }
        return true;
      })
      .filter(_ => {
        if (project) {
          if (_.project.toUpperCase().includes(project.toUpperCase())) return true;
          return false;
        }
        return true;
      })
      .filter(_ => {
        if (gtTvl) {
          if (Number(_.tvlUsd) > Number(gtTvl)) return true;
          return false;
        }
        return true;
      })
      .filter(_ => {
        if (ltTvl) {
          if (Number(_.tvlUsd) < Number(ltTvl)) return true;
          return false;
        }
        return true;
      })
      .filter(_ => {
        const { symbol } = _;
        const tokens = symbol.split('-');

        if (tokens.length < 2) return false;

        const _token0 = token0.toUpperCase();
        const _token1 = token1.toUpperCase();

        if (_token0) {
          if (_token1) {
            if (tokens[0].includes(_token0) && tokens[1].includes(_token1)) return true;
            if (tokens[0].includes(_token1) && tokens[1].includes(_token0)) return true;
            return false;
          } else {
            if (tokens[0].includes(_token0) || tokens[1].includes(_token0)) return true;
            return false;
          }
        } else {
          if (_token1) {
            if (tokens[0].includes(_token1) || tokens[1].includes(_token1)) return true;
            return false;
          }
        }

        return true;
      })
      .forEach((_, i) => {
        const fee = _.poolMeta ? _.poolMeta.split(', ')[0] : '';

        data.push({
          key: i,
          'pool': `${_.symbol}${fee ? `(${fee})` : ''}`,
          'symbol': _.symbol,
          'apyBase': _.apyBase,
          'apy': _.apy,
          'apyPct7D': _.apyPct7D,
          'project': _.project,
          'chain': _.chain,
          'volumeUsd1d': nFormatter(_.volumeUsd1d),
          'tvlUsd': nFormatter(_.tvlUsd),
          'underlyingTokens': _.underlyingTokens,
          'url': `${config.url}${_.pool}`
        });
      });

    setTableData(data);
  };

  const nFormatter = (num, digits = 1) => {
    const lookup = [
      { value: 1, symbol: '' },
      { value: 1e3, symbol: 'k' },
      { value: 1e6, symbol: 'M' },
      { value: 1e9, symbol: 'G' },
      { value: 1e12, symbol: 'T' },
      { value: 1e15, symbol: 'P' },
      { value: 1e18, symbol: 'E' }
    ];
    const rx = /\.0+$|(\.[0-9]*[1-9])0+$/;
    var item = lookup
      .slice()
      .reverse()
      .find(function (item) {
        return num >= item.value;
      });
    return item ? (num / item.value).toFixed(digits).replace(rx, '$1') + item.symbol : '0';
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      tableRef.current();
    }, 200);

    return () => {
      clearTimeout(timer);
    };
  }, [token0, token1, gtTvl, ltTvl, chain, project, pools]);

  useEffect(() => {
    ref.current();
  }, []);

  return (
    <div className="defi-app">
      <div className="defi-token-inputs">
        <div className="defi-token-input">
          <Typography.Text>Token0:</Typography.Text>
          <Input value={token0} onChange={e => setToken0(e.target.value)} />
        </div>
        <div className="defi-token-input">
          <Typography.Text>Token1:</Typography.Text>
          <Input value={token1} onChange={e => setToken1(e.target.value)} />
        </div>
      </div>
      <div className="defi-token-inputs">
        <div className="defi-token-input">
          <Typography.Text>TVL&nbsp;{'>:'}</Typography.Text>
          <Input value={gtTvl} onChange={e => setGtTvl(e.target.value)} />
        </div>
        <div className="defi-token-input">
          <Typography.Text>TVL&nbsp;{'<:'}</Typography.Text>
          <Input value={ltTvl} onChange={e => setLtTvl(e.target.value)} />
        </div>
      </div>
      <div className="defi-token-inputs">
        <div className="defi-token-input">
          <Typography.Text>Chain:</Typography.Text>
          <Input value={chain} onChange={e => setChain(e.target.value)} />
        </div>
        <div className="defi-token-input">
          <Typography.Text>Project:</Typography.Text>
          <Input value={project} onChange={e => setProject(e.target.value)} />
        </div>
      </div>

      <Table columns={tableCols} dataSource={tableData} scroll={{ x: 'max-content' }} pagination={{ pageSize: 100 }} />
    </div>
  );
}

export default App;
